#define MAX_LOCAL_DATA 2304

inline int divRndUpInt(const int n, const int d)
{
    return (n / d) + ((n % d) ? 1 : 0);
}

inline int parityIdxRuntime(const int tid, const int threads)
{
    return (tid * 2) - (threads - 1) * (tid / (threads / 2));
}

inline void mirrorInt(__private int *d, const int sizeD)
{
    if (*d >= sizeD) {
        *d = 2 * sizeD - 2 - *d;
    } else if (*d < 0) {
        *d = -*d;
    }
}

typedef struct {
    int end;
    int stride;
    int last;
} PixelLoaderInt;

inline int PixelLoader_initialize(__private PixelLoaderInt *loader,
                                  const int sizeX, const int sizeY,
                                  const int firstX, const int firstY,
                                  const int checked)
{
    loader->end = checked ? (sizeY * sizeX + firstX) : 0;
    loader->stride = sizeX;
    return firstX + sizeX * firstY;
}

inline void PixelLoader_init(__private PixelLoaderInt *loader,
                             const int sizeX, const int sizeY,
                             const int firstXIn, const int firstY,
                             const int checked)
{
    int firstX = firstXIn;
    mirrorInt(&firstX, sizeX);
    loader->last = PixelLoader_initialize(loader, sizeX, sizeY, firstX, firstY, checked) - sizeX;
}

inline void PixelLoader_clear(__private PixelLoaderInt *loader)
{
    loader->end = 0;
    loader->stride = 0;
    loader->last = 0;
}

inline int PixelLoader_loadFrom(__private PixelLoaderInt *loader,
                                __global const int *input,
                                const int checked)
{
    loader->last += loader->stride;
    if (checked && (loader->last == loader->end)) {
        loader->last -= 2 * loader->stride;
        loader->stride = -loader->stride;
    }
    return input[loader->last];
}

typedef struct {
    int end;
    int strideHighToLow;
    int strideLowToHigh;
    int next;
} BandWriterInt;

inline int BandIO_initialize(__private BandWriterInt *writer,
                             const int imageSizeX, const int imageSizeY,
                             const int firstX, const int firstY,
                             const int checked)
{
    int columnOffset = firstX / 2;
    int verticalStride;

    if (firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUpInt(imageSizeX, 2) * divRndUpInt(imageSizeY, 2);
        writer->strideLowToHigh = (imageSizeX * imageSizeY) / 2;
    } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        writer->strideLowToHigh = divRndUpInt(imageSizeY, 2) * imageSizeX;
    }

    writer->strideHighToLow = verticalStride - writer->strideLowToHigh;

    if (checked) {
        writer->end = columnOffset
                    + (imageSizeY / 2) * verticalStride
                    + (imageSizeY & 1) * writer->strideLowToHigh;
    } else {
        writer->end = 0;
    }

    return columnOffset
         + (firstY / 2) * verticalStride
         + (firstY & 1) * writer->strideLowToHigh;
}

inline void BandWriter_clear(__private BandWriterInt *writer)
{
    writer->end = 0;
    writer->strideHighToLow = 0;
    writer->strideLowToHigh = 0;
    writer->next = 0;
}

inline void BandWriter_init(__private BandWriterInt *writer,
                            const int imageSizeX, const int imageSizeY,
                            const int firstX, const int firstY,
                            const int checked)
{
    if (firstX < imageSizeX) {
        writer->next = BandIO_initialize(writer, imageSizeX, imageSizeY, firstX, firstY, checked);
    } else {
        BandWriter_clear(writer);
    }
}

inline int BandWriter_saveAndUpdate(__private BandWriterInt *writer,
                                    __global int *output,
                                    const int item,
                                    const int stride,
                                    const int checked)
{
    if ((!checked) || (writer->next != writer->end)) {
        output[writer->next] = item;
        writer->next += stride;
    }
    return writer->next;
}

inline int BandWriter_writeLowInto(__private BandWriterInt *writer,
                                   __global int *output,
                                   const int value,
                                   const int checked)
{
    return BandWriter_saveAndUpdate(writer, output, value, writer->strideLowToHigh, checked);
}

inline int BandWriter_writeHighInto(__private BandWriterInt *writer,
                                    __global int *output,
                                    const int value,
                                    const int checked)
{
    return BandWriter_saveAndUpdate(writer, output, value, writer->strideHighToLow, checked);
}

inline int TB_getColumnOffset(const int columnIndexIn, const int oddOffset)
{
    int columnIndex = columnIndexIn + 2;
    return (columnIndex / 2) + ((columnIndex & 1) ? oddOffset : 0);
}

inline void TB_forEachVerticalOdd(__local int *data,
                                  const int columnOffset,
                                  const int verticalStride,
                                  const int sizeYTotal)
{
    const int steps = (sizeYTotal - 1) / 2;
    for (int i = 0; i < steps; i++) {
        const int row = i * 2 + 1;
        const int prev = data[columnOffset + (row - 1) * verticalStride];
        const int next = data[columnOffset + (row + 1) * verticalStride];
        const int idx = columnOffset + row * verticalStride;
        data[idx] = data[idx] - ((prev + next) / 2);
    }
}

inline void TB_forEachVerticalEven(__local int *data,
                                   const int columnOffset,
                                   const int verticalStride,
                                   const int sizeYTotal)
{
    if (sizeYTotal > 3) {
        const int steps = sizeYTotal / 2 - 1;
        for (int i = 0; i < steps; i++) {
            const int row = 2 + i * 2;
            const int prev = data[columnOffset + (row - 1) * verticalStride];
            const int next = data[columnOffset + (row + 1) * verticalStride];
            const int idx = columnOffset + row * verticalStride;
            data[idx] = data[idx] + ((prev + next + 2) / 4);
        }
    }
}

inline void TB_forEachHorizontalOdd(__local int *data,
                                    const int firstLine,
                                    const int numLines,
                                    const int verticalStride,
                                    const int oddOffset,
                                    const int sizeX)
{
    const int tid = (int)get_local_id(0);
    const int count = numLines * verticalStride - 1;
    const int prevOffset = firstLine * verticalStride;
    const int centerOffset = prevOffset + oddOffset;
    const int nextOffset = prevOffset + 1;
    const int steps = count / sizeX;
    const int finalCount = count % sizeX;
    const int finalOffset = count - finalCount;

    for (int i = 0; i < steps; i++) {
        const int idx = i * sizeX + tid;
        const int previous = data[prevOffset + idx];
        const int next = data[nextOffset + idx];
        const int cidx = centerOffset + idx;
        data[cidx] = data[cidx] - ((previous + next) / 2);
    }

    if (tid < finalCount) {
        const int idx = finalOffset + tid;
        const int previous = data[prevOffset + idx];
        const int next = data[nextOffset + idx];
        const int cidx = centerOffset + idx;
        data[cidx] = data[cidx] - ((previous + next) / 2);
    }
}

inline void TB_forEachHorizontalEven(__local int *data,
                                     const int firstLine,
                                     const int numLines,
                                     const int verticalStride,
                                     const int oddOffset,
                                     const int sizeX)
{
    const int tid = (int)get_local_id(0);
    const int count = numLines * verticalStride - 1;
    const int centerOffset = firstLine * verticalStride + 1;
    const int prevOffset = firstLine * verticalStride + oddOffset;
    const int nextOffset = prevOffset + 1;
    const int steps = count / sizeX;
    const int finalCount = count % sizeX;
    const int finalOffset = count - finalCount;

    for (int i = 0; i < steps; i++) {
        const int idx = i * sizeX + tid;
        const int previous = data[prevOffset + idx];
        const int next = data[nextOffset + idx];
        const int cidx = centerOffset + idx;
        data[cidx] = data[cidx] + ((previous + next + 2) / 4);
    }

    if (tid < finalCount) {
        const int idx = finalOffset + tid;
        const int previous = data[prevOffset + idx];
        const int next = data[nextOffset + idx];
        const int cidx = centerOffset + idx;
        data[cidx] = data[cidx] + ((previous + next + 2) / 4);
    }
}

typedef struct {
    PixelLoaderInt loader;
    int offset;
    int pixel0;
    int pixel1;
    int pixel2;
} FDWT53ColumnInt;

inline void FDWT53Column_clear(__private FDWT53ColumnInt *column)
{
    column->offset = 0;
    column->pixel0 = 0;
    column->pixel1 = 0;
    column->pixel2 = 0;
    PixelLoader_clear(&column->loader);
}

inline void initColumn53(__private FDWT53ColumnInt *column,
                         __global const int *input,
                         const int sizeX, const int sizeY,
                         const int colIndex, const int firstY,
                         const int checkedLoads,
                         const int groupX,
                         const int groupY,
                         const int winSX,
                         const int oddOffset)
{
    column->offset = TB_getColumnOffset(colIndex, oddOffset);
    const int firstX = groupX * winSX + colIndex;

    if (groupY == 0) {
        PixelLoader_init(&column->loader, sizeX, sizeY, firstX, firstY, checkedLoads);
        column->pixel2 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel1 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel0 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        PixelLoader_init(&column->loader, sizeX, sizeY, firstX, firstY + 1, checkedLoads);
    } else {
        PixelLoader_init(&column->loader, sizeX, sizeY, firstX, firstY - 2, checkedLoads);
        column->pixel0 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel1 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel2 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
    }
}

inline void loadAndVerticallyTransform53(__private FDWT53ColumnInt *column,
                                         __global const int *input,
                                         __local int *buffer,
                                         const int verticalStride,
                                         const int winSY,
                                         const int checkedLoads)
{
    buffer[column->offset + 0 * verticalStride] = column->pixel0;
    buffer[column->offset + 1 * verticalStride] = column->pixel1;
    buffer[column->offset + 2 * verticalStride] = column->pixel2;

    for (int i = 3; i < (3 + winSY); i++) {
        buffer[column->offset + i * verticalStride] =
            PixelLoader_loadFrom(&column->loader, input, checkedLoads);
    }

    column->pixel0 = buffer[column->offset + (winSY + 0) * verticalStride];
    column->pixel1 = buffer[column->offset + (winSY + 1) * verticalStride];
    column->pixel2 = buffer[column->offset + (winSY + 2) * verticalStride];

    TB_forEachVerticalOdd(buffer, column->offset, verticalStride, winSY + 3);
    TB_forEachVerticalEven(buffer, column->offset, verticalStride, winSY + 3);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    const int x = (int)get_global_id(0);
    if (x < pixels) {
        const int offset = x * 3;
        d_r[x] = (int)d_src[offset + 0] - 128;
        d_g[x] = (int)d_src[offset + 1] - 128;
        d_b[x] = (int)d_src[offset + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    const int x = (int)get_global_id(0);
    if (x < pixels) {
        d_c[x] = (int)d_src[x] - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    const int tid = (int)get_local_id(0);
    const int groupX = (int)get_group_id(0);
    const int groupY = (int)get_group_id(1);

    const int verticalStride = 2 + (WIN_SX / 2);
    const int bufferSize = verticalStride * (WIN_SY + 3);
    const int padding = 32 - ((bufferSize + 16) % 32);
    const int oddOffset = bufferSize + padding;

    __local int buffer[MAX_LOCAL_DATA];

    const int maxX = (groupX + 1) * WIN_SX + 1;
    const int maxY = (groupY + 1) * WIN_SY * winSteps + 1;
    const int atRightBoundary = (maxX >= sizeX);
    const int atBottomBoundary = (maxY >= sizeY);

    const int checkedLoads = atBottomBoundary ? 1 : 0;
    const int checkedWrites = (atBottomBoundary || atRightBoundary) ? 1 : 0;

    FDWT53ColumnInt column;
    FDWT53ColumnInt boundaryColumn;

    const int firstY = groupY * WIN_SY * winSteps;

    initColumn53(&column, input, sizeX, sizeY, tid, firstY,
                 checkedLoads, groupX, groupY, WIN_SX, oddOffset);

    FDWT53Column_clear(&boundaryColumn);
    if (tid < 3) {
        const int colId = tid + ((tid == 0) ? WIN_SX : -3);
        initColumn53(&boundaryColumn, input, sizeX, sizeY, colId, firstY,
                     checkedLoads, groupX, groupY, WIN_SX, oddOffset);
    }

    const int outColumnIndex = parityIdxRuntime(tid, WIN_SX);
    const int outColumnOffset = TB_getColumnOffset(outColumnIndex, oddOffset);
    const int outputFirstX = groupX * WIN_SX + outColumnIndex;

    BandWriterInt writer;
    BandWriter_init(&writer, sizeX, sizeY, outputFirstX, firstY, checkedWrites);

    for (int w = 0; w < winSteps; w++) {
        loadAndVerticallyTransform53(&column, input, buffer, verticalStride, WIN_SY, checkedLoads);
        if (tid < 3) {
            loadAndVerticallyTransform53(&boundaryColumn, input, buffer, verticalStride, WIN_SY, checkedLoads);
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        TB_forEachHorizontalOdd(buffer, 2, WIN_SY, verticalStride, oddOffset, WIN_SX);

        barrier(CLK_LOCAL_MEM_FENCE);

        TB_forEachHorizontalEven(buffer, 2, WIN_SY, verticalStride, oddOffset, WIN_SX);

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int r = 2; r < (2 + WIN_SY); r += 2) {
            BandWriter_writeLowInto(&writer, output,
                                    buffer[outColumnOffset + r * verticalStride],
                                    checkedWrites);
            BandWriter_writeHighInto(&writer, output,
                                     buffer[outColumnOffset + (r + 1) * verticalStride],
                                     checkedWrites);
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }
}
